func (d *dbBasePostgres) HasReturningID(mi *models.ModelInfo, query *string) bool {
	fi := mi.Fields.Pk
	if fi.FieldType&IsPositiveIntegerField == 0 && fi.FieldType&IsIntegerField == 0 {
		return false
	}

	if query != nil {
		*query = fmt.Sprintf(`%s RETURNING "%s"`, *query, fi.Column)
	}
	return true
}
